namespace sv_c579c6236038424b9b50a718a86df58e.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service (one per SignalR circuit) that holds the currently selected
/// warehouse and notifies all subscribed components when it changes.
/// </summary>
public sealed class WarehouseStateService : IDisposable
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A" },
        new() { Id = "WH-B", Name = "Warehouse B" },
        new() { Id = "WH-C", Name = "Warehouse C" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public WarehouseInfo CurrentWarehouse =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId);

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId)
            return;

        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }

    public void Dispose() => OnChange = null;
}

namespace sv_c579c6236038424b9b50a718a86df58e.Services;

/// <summary>
/// Scoped service (one per SignalR circuit) that tracks low-stock alert counts.
/// Components subscribe to <see cref="OnAlertDataChanged"/> to be notified when
/// new polling data arrives — any component can trigger the refresh and all
/// subscribers are updated.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();

    public int CurrentLowStockCount { get; private set; }

    /// <summary>
    /// Fired after <see cref="RefreshAsync"/> completes so every subscriber
    /// (sidebar badge, dashboard panel, etc.) can re-render.
    /// </summary>
    public event Action? OnAlertDataChanged;

    /// <summary>
    /// Simulates a database query returning a random low-stock count for the
    /// given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB access
        var count = _random.Next(0, 16); // 0–15 inclusive
        return Task.FromResult(count);
    }

    /// <summary>
    /// Polls for the latest alert count and notifies all subscribers.
    /// Called by the polling timer on the dashboard page.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        CurrentLowStockCount = await GetLowStockCountAsync(warehouseId);
        OnAlertDataChanged?.Invoke();
    }

    public void Dispose() => OnAlertDataChanged = null;
}

