@using sv_c579c6236038424b9b50a718a86df58e.Services
@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@implements IDisposable

<div class="warehouse-selector">
    <label class="form-label text-white mb-1" for="warehouseSelect">Current Warehouse</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseStateService.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_c579c6236038424b9b50a718a86df58e.Services
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

<span class="badge rounded-pill @BadgeClass">@AlertService.CurrentLowStockCount</span>

@code {
    private string BadgeClass =>
        AlertService.CurrentLowStockCount switch
        {
            > 10 => "bg-danger",
            > 5  => "bg-warning text-dark",
            > 0  => "bg-info",
            _    => "bg-success"
        };

    protected override void OnInitialized()
    {
        AlertService.OnAlertDataChanged += OnDataChanged;
    }

    private void OnDataChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertDataChanged -= OnDataChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_c579c6236038424b9b50a718a86df58e.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouse.Name</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouse.Name</h5>
        <p class="card-text">
            Low-stock items:
            <span class="fs-3 fw-bold @TextClass">@AlertService.CurrentLowStockCount</span>
        </p>
        <p class="text-muted mb-0">
            Polling every 10 seconds. Last refresh: @_lastRefresh?.ToString("HH:mm:ss")
        </p>
    </div>
</div>

@code {
    private Timer? _pollingTimer;
    private DateTime? _lastRefresh;

    private string TextClass =>
        AlertService.CurrentLowStockCount switch
        {
            > 10 => "text-danger",
            > 5  => "text-warning",
            > 0  => "text-info",
            _    => "text-success"
        };

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertDataChanged += OnAlertDataChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await PollAsync();
            StartPolling();
        }
    }

    private void StartPolling()
    {
        _pollingTimer?.Dispose();
        _pollingTimer = new Timer(async _ =>
        {
            await PollAsync();
        }, null, TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(10));
    }

    private async Task PollAsync()
    {
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        _lastRefresh = DateTime.Now;
        await InvokeAsync(StateHasChanged);
    }

    private async void OnWarehouseChanged()
    {
        // Immediately refresh when warehouse changes
        await PollAsync();
    }

    private void OnAlertDataChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        _pollingTimer?.Dispose();
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertDataChanged -= OnAlertDataChanged;
    }
}

